const input = $input.first().json;
const body = input.body || input;

let entry, value, message;

try {
  entry = body.entry || input.entry;
  if (!entry || !entry[0]) throw new Error('No entry');
  const changes = entry[0].changes;
  if (!changes || !changes[0]) throw new Error('No changes');
  value = changes[0].value;
  if (value.statuses) {
    return [{ json: { skip: true, reason: 'Status update' } }];
  }
  if (!value.messages || !value.messages[0]) {
    return [{ json: { skip: true, reason: 'No messages' } }];
  }
  message = value.messages[0];
} catch (e) {
  if (body.test_message) {
    return [{ json: { from: body.from || '919999999999', timestamp: String(Math.floor(Date.now() / 1000)), messageType: 'text', messageBody: body.test_message, hasMedia: false, mediaId: '', contactName: body.contact_name || 'Test User', fileData: body.fileData || '', fileName: body.fileName || '', fileType: body.fileType || '' } }];
  }
  return [{ json: { skip: true, reason: 'Invalid: ' + e.message } }];
}

const contacts = value.contacts || [];
const contactName = contacts[0] && contacts[0].profile ? contacts[0].profile.name : 'Unknown';

const result = { from: message.from, timestamp: message.timestamp, messageType: message.type, messageBody: '', hasMedia: false, mediaId: '', mediaMimeType: '', contactName: contactName };

if (message.type === 'text') {
  result.messageBody = message.text.body;
} else if (message.type === 'image') {
  result.messageBody = (message.image.caption) || '[Image received]';
  result.hasMedia = true;
  result.mediaId = message.image.id;
} else if (message.type === 'video') {
  result.messageBody = (message.video.caption) || '[Video received]';
  result.hasMedia = true;
  result.mediaId = message.video.id;
} else if (message.type === 'document') {
  result.messageBody = (message.document.caption) || (message.document.filename) || '[Document received]';
  result.hasMedia = true;
  result.mediaId = message.document.id;
  result.fileName = message.document.filename;
} else if (message.type === 'audio') {
  result.messageBody = '[Audio message]';
  result.hasMedia = true;
  result.mediaId = message.audio.id;
} else {
  result.messageBody = '[Unsupported: ' + message.type + ']';
}

return [{ json: result }];

