const aiResponse = $input.first().json;
let responseText = '';

// Handle Gemini API response format
if (aiResponse.candidates && aiResponse.candidates[0]) {
  responseText = aiResponse.candidates[0].content.parts[0].text;
} else if (aiResponse.message && aiResponse.message.content) {
  responseText = aiResponse.message.content;
} else if (aiResponse.text) {
  responseText = aiResponse.text;
} else {
  responseText = JSON.stringify(aiResponse);
}

responseText = responseText.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();

const jsonMatch = responseText.match(/\{[\s\S]*\}/);
if (jsonMatch) responseText = jsonMatch[0];

try {
  const parsed = JSON.parse(responseText);
  const validCats = ['calendar','sheet','email','drive','notion','trello','slack'];
  if (!validCats.includes(parsed.category)) parsed.category = 'unknown';

  const ext = $('Extract Message');
  if (ext) {
    parsed._from = ext.first().json.from;
    parsed._contactName = ext.first().json.contactName;
    parsed._messageType = ext.first().json.messageType;
    parsed._hasMedia = ext.first().json.hasMedia;
    parsed._mediaId = ext.first().json.mediaId;
    parsed._originalMessage = ext.first().json.messageBody;
    parsed._fileName = ext.first().json.fileName || '';
  }
  return [{ json: parsed }];
} catch (e) {
  return [{ json: { category: 'unknown', error: e.message, rawResponse: responseText, _from: '', _contactName: '' } }];
}

const input = $input.first().json;
let msg = '';

if (input.category === 'calendar') {
  msg = 'Calendar Event Created!\nTitle: ' + input.title + '\nDate: ' + input.date + '\nTime: ' + (input.time || '09:00');
} else if (input.category === 'sheet') {
  msg = 'Data Added to Spreadsheet!\nSheet: ' + (input.sheetName || 'General') + '\nFields: ' + Object.keys(input.data || {}).join(', ');
} else if (input.category === 'email') {
  msg = 'Email Sent!\nTo: ' + input.to + '\nSubject: ' + input.subject;
} else if (input.category === 'drive') {
  msg = 'File Saved to Drive!\nFile: ' + (input.filename || 'upload') + '\nFolder: ' + (input.folder || 'WhatsApp Uploads');
} else if (input.category === 'notion') {
  msg = 'Notion Page Created!\nTitle: ' + input.title;
} else if (input.category === 'trello') {
  msg = 'Trello Card Created!\nTask: ' + input.title + '\nList: ' + (input.list || 'To Do');
} else if (input.category === 'slack') {
  msg = 'Slack Message Sent!\nChannel: ' + (input.channel || '#general');
} else {
  msg = 'Could not classify this message. Please try again.';
}

return [{ json: { ...input, confirmationMessage: msg } }];

const data = $input.first().json;
const now = new Date().toISOString();
const sheetRow = { Timestamp: now, From: data._contactName || 'Unknown', Phone: data._from || '' };
if (data.data) { Object.assign(sheetRow, data.data); }
return [{ json: sheetRow }];

const data = $input.first().json;
let binary;
if (data.fileData && data.fileData.startsWith('data:')) {
  const parts = data.fileData.split(',');
  const meta = parts[0];
  const base64Data = parts[1];
  const mimeType = meta.match(/data:(.*?);/)[1];
  const ext = mimeType.split('/')[1] || 'bin';
  const fileName = data.filename || ('upload.' + ext);
  binary = { data: { data: base64Data, mimeType: mimeType, fileName: fileName, fileExtension: ext } };
} else {
  const content = 'From: ' + (data._contactName || 'Dashboard') + '\nDate: ' + new Date().toISOString() + '\nContent: ' + (data.description || data._originalMessage || 'No content');
  const buffer = Buffer.from(content, 'utf-8');
  binary = { data: { data: buffer.toString('base64'), mimeType: 'text/plain', fileName: (data.filename || 'note') + '.txt', fileExtension: 'txt' } };
}
return [{ json: data, binary: binary }];

const data = $input.first().json;
return [{ json: { ...data, category:'unknown', confirmationMessage: 'Could not understand. Try:
- Schedule meeting tomorrow 3pm
- Add expense Coffee 200
- Send email to x@y.com
- Send any file/image
- Note: meeting discussion
- Task: do something by Friday
- Notify team about update' } }];
